section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/api-rate-limiting.json",
  "title": "API Rate Limiting",
  "type": "object",
  "required": [
    "artefact_id",
    "api_id",
    "algorithm",
    "tiers",
    "per_endpoint_multipliers",
    "backend",
    "headers",
    "over_limit_response",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "api_id": {
      "type": "string",
      "description": "service id or repo slug",
      "minLength": 1
    },
    "algorithm": {
      "type": "string",
      "description": "sliding-window|token-bucket|fixed-window|leaky-bucket",
      "minLength": 1
    },
    "tiers": {
      "type": "array",
      "description": "list of {tier, requests_per_minute, burst}",
      "minItems": 1
    },
    "per_endpoint_multipliers": {
      "type": "object",
      "description": "map of endpoint pattern \u2192 multiplier"
    },
    "backend": {
      "type": "string",
      "description": "redis|memcached|in-memory|cloud-managed",
      "minLength": 1
    },
    "headers": {
      "type": "array",
      "description": "list of response header names emitted (Retry-After, RateLimit-Limit, RateLimit-Remaining, RateLimit-Reset)",
      "minItems": 1
    },
    "over_limit_response": {
      "type": "object",
      "description": "{status, body_template} for 429 response"
    }
  },
  "additionalProperties": false
}
